#include "msconnector/transaction_state.h"
void msconnector_transaction_state_init(msconnector_transaction_state *state, const char *transaction_id) { if (state) { state->transaction_id = transaction_id; state->connection_processed = 0; state->uri_processed = 0; state->request_headers_processed = 0; state->request_body_processed = 0; state->response_headers_processed = 0; state->response_body_processed = 0; state->logging_processed = 0; state->response_headers_committed = 0; state->response_body_started = 0; state->response_body_truncated = 0; } }
int msconnector_transaction_state_mark_phase(msconnector_transaction_state *s, enum msconnector_phase p) { if (!s) return 0; switch (p) { case MSCONNECTOR_PHASE_CONNECTION: s->connection_processed = 1; return 1; case MSCONNECTOR_PHASE_URI: s->uri_processed = 1; return 1; case MSCONNECTOR_PHASE_REQUEST_HEADERS: s->request_headers_processed = 1; return 1; case MSCONNECTOR_PHASE_REQUEST_BODY: s->request_body_processed = 1; return 1; case MSCONNECTOR_PHASE_RESPONSE_HEADERS: s->response_headers_processed = 1; return 1; case MSCONNECTOR_PHASE_RESPONSE_BODY: s->response_body_processed = 1; return 1; case MSCONNECTOR_PHASE_LOGGING: s->logging_processed = 1; return 1; } return 0; }
int msconnector_transaction_state_phase_processed(const msconnector_transaction_state *s, enum msconnector_phase p) { if (!s) return 0; switch (p) { case MSCONNECTOR_PHASE_CONNECTION: return s->connection_processed; case MSCONNECTOR_PHASE_URI: return s->uri_processed; case MSCONNECTOR_PHASE_REQUEST_HEADERS: return s->request_headers_processed; case MSCONNECTOR_PHASE_REQUEST_BODY: return s->request_body_processed; case MSCONNECTOR_PHASE_RESPONSE_HEADERS: return s->response_headers_processed; case MSCONNECTOR_PHASE_RESPONSE_BODY: return s->response_body_processed; case MSCONNECTOR_PHASE_LOGGING: return s->logging_processed; } return 0; }
const char *msconnector_phase_name(enum msconnector_phase phase) { switch (phase) { case MSCONNECTOR_PHASE_CONNECTION: return "connection"; case MSCONNECTOR_PHASE_URI: return "uri"; case MSCONNECTOR_PHASE_REQUEST_HEADERS: return "request_headers"; case MSCONNECTOR_PHASE_REQUEST_BODY: return "request_body"; case MSCONNECTOR_PHASE_RESPONSE_HEADERS: return "response_headers"; case MSCONNECTOR_PHASE_RESPONSE_BODY: return "response_body"; case MSCONNECTOR_PHASE_LOGGING: return "logging"; } return "unknown"; }
